package entity_test

import (
	"math"
	"testing"

	"github.com/yourorg/bean-brew/internal/entity"
)

// TestOrderCalculateTotal_EdgeCases contains edge‑case scenarios that are **not**
// covered by the existing TestUnitOrderCalculateTotal* suite (empty, single, large
// order, etc.).  The goal is to verify that `Order.CalculateTotal()` behaves
// correctly when it meets unusual but possible data shapes.
//
// The cases are:
//
//   1. **Zero‑quantity items** – they must not affect the total.
//   2. **Negative quantity** – the method is a pure arithmetic routine, so it
//      will subtract the amount; we only check the arithmetic result (validation
//      of the sign is performed elsewhere in `Order.Validate()`).
//   3. **High‑precision prices** – floating‑point rounding must be preserved.
//   4. **Duplicate product IDs** – the total is the sum of all items, regardless
//      of duplication.
//   5. **Very large numbers** – ensure the calculation does not overflow the
//      `float64` range used for `Order.Total` (the test stays well below the
//      overflow limit but uses big values to stress the routine).
//
func TestOrderCalculateTotal_EdgeCases(t *testing.T) {
	t.Parallel()

	type item struct {
		productID int64
		qty       int
		price     float64
	}
	tests := []struct {
		name     string
		items    []item
		expected float64
	}{
		{
			name: "zero_quantity_ignored",
			items: []item{
				{productID: 1, qty: 0, price: 100.0}, // should contribute 0
				{productID: 2, qty: 3, price: 20.0},
			},
			expected: 60.0, // 3 * 20
		},
		{
			name: "negative_quantity_subtracts",
			items: []item{
				{productID: 1, qty: 2, price: 50.0},
				{productID: 2, qty: -1, price: 30.0}, // -30
			},
			expected: 70.0, // (2*50) + (-1*30)
		},
		{
			name: "high_precision_prices",
			items: []item{
				{productID: 1, qty: 1, price: 0.123456789},
				{productID: 2, qty: 2, price: 0.987654321},
			},
			// 1*0.123456789 + 2*0.987654321 = 2.098765431
			expected: 2.098765431,
		},
		{
			name: "duplicate_product_ids",
			items: []item{
				{productID: 42, qty: 1, price: 10.0},
				{productID: 42, qty: 2, price: 10.0},
				{productID: 42, qty: 3, price: 10.0},
			},
			expected: 60.0, // (1+2+3)*10
		},
		{
			name: "very_large_numbers_still_correct",
			items: []item{
				{productID: 1, qty: 1_000_000, price: 1_000_000.0},
				{productID: 2, qty: 2_000_000, price: 0.5},
			},
			// 1_000_000 * 1_000_000 = 1e12
			// 2_000_000 * 0.5      = 1e6
			// total = 1_001_000_000_000
			expected: 1_001_000_000_000.0,
		},
	}

	for _, tt := range tests {
		tt := tt // capture range variable
		t.Run(tt.name, func(t *testing.T) {
			t.Parallel()

			// Build the Order with the slice of entity.OrderItem expected by the
			// production code.
			o := &entity.Order{
				Items: make([]entity.OrderItem, 0, len(tt.items)),
			}
			for _, it := range tt.items {
				o.Items = append(o.Items, entity.OrderItem{
					ProductID: it.productID,
					Quantity:  it.qty,
					UnitPrice: it.price,
				})
			}

			// Act – the method under test.
			o.CalculateTotal()

			// Assert – use a tolerance for floating‑point comparison where needed.
			const eps = 1e-9
			if math.Abs(o.Total-tt.expected) > eps {
				t.Fatalf("unexpected total: got %v, want %v", o.Total, tt.expected)
			}
		})
	}
}
```

### Why this test does **not** duplicate existing ones

| Existing test | What it covers | What this test adds |
|---------------|----------------|---------------------|
| `TestUnitOrderCalculateTotal` | A “normal” order with a few items (positive qty, normal prices). | Edge‑cases listed above (zero/negative qty, high‑precision prices, duplicate IDs, huge numbers). |
| `TestUnitOrderCalculateTotalEmpty` | Empty slice → total = 0. | Zero‑quantity item (non‑empty slice but total = 0) and large‑number overflow check. |
| `TestUnitOrderCalculateTotalSingleItem` | One item, normal values. | High‑precision price and negative quantity. |
| `TestUnitOrderCalculateTotalLargeOrder` | Many items, normal values. | Duplicate IDs and very large numeric values (stress test). |

Thus the suite stays **complementary**: it exercises the same `CalculateTotal` implementation but with data shapes that were not previously verified, ensuring the routine is robust against unusual input while still keeping the test fast and deterministic.

