```go
package handler_test

import (
	"bytes"
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"path"
	"strconv"
	"testing"
	"time"

	"beanbrew/internal/entity"
	"beanbrew/internal/handler"
	"beanbrew/internal/repository/sqlite"
	"beanbrew/internal/usecase"
)

// ---------------------------------------------------------------------
// Helper structs that mirror the request payloads used by the API.
// ---------------------------------------------------------------------
type createCategoryReq struct {
	Name        string `json:"name"`
	Description string `json:"description"`
	SortOrder   int    `json:"sort_order"`
}

type createProductReq struct {
	Name        string  `json:"name"`
	Description string  `json:"description"`
	Price       float64 `json:"price"`
	CategoryID  int64   `json:"category_id"`
	ImageURL    string  `json:"image_url"`
	Active      bool    `json:"active"`
}

type createOrderReq struct {
	Items []entity.OrderItem `json:"items"` // OrderItem is defined in the entity package
}

// ---------------------------------------------------------------------
// TestAPIOrderFullFlow
//
// Flow:
//   1. POST   /api/v1/categories          → create a category
//   2. POST   /api/v1/products            → create a product that belongs to the category
//   3. POST   /api/v1/orders              → create an order that contains the product
//   4. POST   /api/v1/orders/{id}/cancel  → cancel the order
//   5. GET    /api/v1/orders/{id}         → verify the status is \"cancelled\"
// ---------------------------------------------------------------------
func TestAPIOrderFullFlow(t *testing.T) {
	// -------------------------------------------------------------
	// 1️⃣  Set up a fresh in‑memory SQLite DB and the full HTTP stack.
	// -------------------------------------------------------------
	db, err := sqlite.NewInMemory()
	if err != nil {
		t.Fatalf("cannot create in‑memory DB: %v", err)
	}
	if err := sqlite.Migrate(db); err != nil {
		t.Fatalf("migration failed: %v", err)
	}
	if err := sqlite.Seed(db); err != nil {
		t.Fatalf("seed failed: %v", err)
	}

	// Build the use‑cases (they depend on the concrete SQLite repos)
	productUC := usecase.NewProductUsecase(db)
	categoryUC := usecase.NewCategoryUsecase(db)
	orderUC := usecase.NewOrderUsecase(db)

	// Build the HTTP handler tree (chi router)
	h := handler.NewRouter(productUC, categoryUC, nil, orderUC)

	ts := httptest.NewServer(h)
	defer ts.Close()

	// -------------------------------------------------------------
	// 2️⃣  Create a category.
	// -------------------------------------------------------------
	catPayload := createCategoryReq{
		Name:        "Espresso",
		Description: "All things espresso",
		SortOrder:   1,
	}
	catBody, _ := json.Marshal(catPayload)

	resp, err := http.Post(ts.URL+"/api/v1/categories", "application/json", bytes.NewReader(catBody))
	if err != nil {
		t.Fatalf("POST /categories request failed: %v", err)
	}
	if resp.StatusCode != http.StatusCreated {
		t.Fatalf("expected 201 Created for category, got %d", resp.StatusCode)
	}
	var catResp struct {
		ID int64 `json:"id"`
	}
	if err := json.NewDecoder(resp.Body).Decode(&catResp); err != nil {
		t.Fatalf("cannot decode category response: %v", err)
	}
	resp.Body.Close()

	// -------------------------------------------------------------
	// 3️⃣  Create a product that belongs to the newly created category.
	// -------------------------------------------------------------
	prodPayload := createProductReq{
		Name:        "Classic Espresso",
		Description: "Rich, full‑bodied espresso shot",
		Price:       320.0,
		CategoryID:  catResp.ID,
		ImageURL:    "https://example.com/espresso.png",
		Active:      true,
	}
	prodBody, _ := json.Marshal(prodPayload)

	resp, err = http.Post(ts.URL+"/api/v1/products", "application/json", bytes.NewReader(prodBody))
	if err != nil {
		t.Fatalf("POST /products request failed: %v", err)
	}
	if resp.StatusCode != http.StatusCreated {
		t.Fatalf("expected 201 Created for product, got %d", resp.StatusCode)
	}
	var prodResp struct {
		ID int64 `json:"id"`
	}
	if err := json.NewDecoder(resp.Body).Decode(&prodResp); err != nil {
		t.Fatalf("cannot decode product response: %v", err)
	}
	resp.Body.Close()

	// -------------------------------------------------------------
	// 4️⃣  Create an order that contains the product.
	// -------------------------------------------------------------
	orderPayload := createOrderReq{
		Items: []entity.OrderItem{
			{
				ProductID: prodResp.ID,
				Quantity:  2, // 2 × 320 = 640
			},
		},
	}
	orderBody, _ := json.Marshal(orderPayload)

	resp, err = http.Post(ts.URL+"/api/v1/orders", "application/json", bytes.NewReader(orderBody))
	if err != nil {
		t.Fatalf("POST /orders request failed: %v", err)
	}
	if resp.StatusCode != http.StatusCreated {
		t.Fatalf("expected 201 Created for order, got %d", resp.StatusCode)
	}
	var orderResp struct {
		ID    int64   `json:"id"`
		Total float64 `json:"total"`
	}
	if err := json.NewDecoder(resp.Body).Decode(&orderResp); err != nil {
		t.Fatalf("cannot decode order response: %v", err)
	}
	resp.Body.Close()

	// Verify that the total was calculated correctly (2 × 320 = 640)
	if orderResp.Total != 640 {
		t.Fatalf("order total mismatch: expected 640, got %v", orderResp.Total)
	}

	// -------------------------------------------------------------
	// 5️⃣  Cancel the order.
	// -------------------------------------------------------------
	cancelURL := ts.URL + path.Join("/api/v1/orders", strconv.FormatInt(orderResp.ID, 10), "cancel")
	req, err := http.NewRequest(http.MethodPost, cancelURL, nil)
	if err != nil {
		t.Fatalf("cannot build cancel request: %v", err)
	}
	resp, err = http.DefaultClient.Do(req)
	if err != nil {
		t.Fatalf("POST /orders/{id}/cancel request failed: %v", err)
	}
	if resp.StatusCode != http.StatusOK {
		t.Fatalf("expected 200 OK on cancel, got %d", resp.StatusCode)
	}
	resp.Body.Close()

	// -------------------------------------------------------------
	// 6️⃣  Fetch the order and assert its status is \"cancelled\".
	// -------------------------------------------------------------
	getURL := ts.URL + path.Join("/api/v1/orders", strconv.FormatInt(orderResp.ID, 10))
	resp, err = http.Get(getURL)
	if err != nil {
		t.Fatalf("GET /orders/{id} request failed: %v", err)
	}
	if resp.StatusCode != http.StatusOK {
		t.Fatalf("expected 200 OK on get order, got %d", resp.StatusCode)
	}
	var fetched struct {
		ID     int64          `json:"id"`
		Status entity.OrderStatus `json:"status"`
		Total  float64        `json:"total"`
		Items  []entity.OrderItem `json:"items"`
		CreatedAt time.Time   `json:"created_at"`
	}
	if err := json.NewDecoder(resp.Body).Decode(&fetched); err != nil {
		t.Fatalf("cannot decode fetched order: %v", err)
	}
	resp.Body.Close()

	if fetched.Status != entity.OrderStatusCancelled {
		t.Fatalf("order status mismatch: expected %q, got %q", entity.OrderStatusCancelled, fetched.Status)
	}
}
```

### What the test does

| Step | Action | Expected outcome |
|------|--------|------------------|
| **1** | Spin up an **in‑memory SQLite** DB, run migrations & seed data, build the real use‑cases and the full HTTP router. | Isolated environment – no external services. |
| **2** | `POST /api/v1/categories` – create a category. | `201 Created` and a JSON body containing the new `id`. |
| **3** | `POST /api/v1/products` – create a product that references the category created in step 2. | `201 Created` and a JSON body with the product `id`. |
| **4** | `POST /api/v1/orders` – create an order with **2** units of the product (price = 320). |

## Что «тормозит» текущий набор тестов  

| Уровень | Что наблюдаем | Почему это проблемно |
|--------|---------------|----------------------|
| **Unit** | 32 быстрых теста, но почти все из них пишут `setupTestDB()` и `setupTestServer()` даже там, где это не нужно (например, только проверка валидации). | Создаётся лишний SQLite‑инстанс → лишние затраты на миграцию и очистку. |
| **Integration** | Тесты используют один и тот же in‑memory DB в рамках функции, а `TestIntegrationProductSearch` зависит от порядка вставки и от поведения `LIKE` с кириллицей. | Флюктуация, скрытые зависимости, иногда падает в CI. |
| **API** | Тесты «склеивают» несколько действий (создать категорию → продукт → заказ) в один большой сценарий. | При падении трудно понять, где именно сломалось. |
| **Общее** | Тесты почти не используют параллелизм (`t.Parallel()`), а в репозитории есть дублирование кода создания мок‑объектов (хотя они и не используются). | Потенциально можно ускорить в 2‑3 раза без изменения поведения. |

---

## Конкретные действия, которые сразу дадут ускорение и надёжность

### 1. Параллелизировать **unit‑тесты**
```go
func TestUnitProductValidate(t *testing.T) {
    t.Parallel()               // <-- добавить в каждый TestUnit* (можно в TestMain)
    cases := []struct{…}{…}
    for _, tc := range cases {
        tc := tc               // захватить переменную
        t.Run(tc.name, func(t *testing.T) {
            t.Parallel()
            // …тело теста…
        })
    }
}
```
*Плюс*: каждый под‑тест работает в отдельной горутине, а `go test` уже умеет ограничивать количество одновременно запущенных тестов (`-parallel=N`). На обычном ноутбуке 8‑12 ядров дают ускорение почти в 3‑4 раза.

### 2. Выделить **общий тест‑хелпер** для SQLite
Создать файл `internal/repository/sqlite/testhelper.go` (уже есть, но расширить) с функцией:

```go
func NewTestDB(t *testing.T) *sql.DB {
    t.Helper()
    db, err := sql.Open("sqlite3", ":memory:")
    if err != nil { t.Fatalf("open db: %v", err) }

    // миграции + сид
    if err := migrations.Apply(db); err != nil {
        t.Fatalf("migrate: %v", err)
    }
    if err := seed.Seed(db); err != nil {
        t.Fatalf("seed: %v", err)
    }

    t.Cleanup(func() { db.Close() })
    return db
}
```

Тогда в тестах, где нужен только репозиторий (например, `TestUnitOrderValidate`), можно писать:

```go
func TestUnitOrderValidate(t *testing.T) {
    t.Parallel()
    db := NewTestDB(t)               // без лишних серверов
    repo := sqlite.NewOrderRepository(db)
    // …тестируем только бизнес‑логику репозитория…
}
```

*Плюс*: один миграционный вызов вместо пяти‑десяти, меньше IO, меньше кода в каждом тесте.

### 3. **Изолировать** каждый интеграционный тест в собственный DB
Сейчас несколько тестов делят один `*sql.DB`. Переписать их так:

```go
func TestIntegrationProductSearch(t *testing.T) {
    t.Parallel()
    db := NewTestDB(t)               // отдельный ин‑мем DB
    repo := sqlite.NewProductRepository(db)

    // подготовка данных – **явно** задаём порядок
    if err := repo.Create(ctx, productA); err != nil { t.Fatalf(...) }
    if err := repo.Create(ctx, productB); err != nil { t.Fatalf(...) }

    // проверяем поиск
    got, err := repo.Search(ctx, "Тест")
    if err != nil { t.Fatalf(...) }
    if diff := cmp.Diff([]Product{productA}, got); diff != "" { t.Errorf(diff) }
}
```

*Плюс*: отсутствие скрытых зависимостей, тест перестаёт быть «флюктуационным».  

**Что делать с кириллическим `LIKE`** – добавить `COLLATE NOCASE` в запрос или использовать `LIKE ? ESCAPE '\'` с параметром `%` и `unicode.Normalize`. Если это слишком тяжело, просто **отключить** этот тест в обычном CI и запускать его в отдельном «slow»‑job’е.

### 4. Разделить **API‑тесты** на «мелкие» и «сквозные» сценарии
*Мелкие* (unit‑уровень) – проверяют только один эндпоинт, используют `httptest.NewRecorder` без реального сервера.  
*Сквозные* – оставляем текущий «order flow», но вынесем его в отдельный пакет `internal/handler/api_test_integration` и пометим build‑тегом `//go:build integration`.

```go
// +build integration

func TestAPIOrderFlow(t *testing.T) {
    // запускаем только в CI с `go test -tags=integration ./...`
}
```

*Плюс*: обычный `go test ./...` будет быстрее (меньше сетевых запросов), а тяжёлый сценарий будет запускаться только в отдельном job’е.

### 5. Добавить **флаг `-short`** и использовать его в тестах, которые требуют реального DB
```go
func TestIntegrationProductSearch(t *testing.T) {
    if testing.Short() {
        t.Skip("skip integration test in short mode")
    }
    // …тело теста…
}
```
Тогда `go test -short ./...` (например, в локальном запуске) будет выполнять только unit‑тесты, а CI будет запускать без `-short`.

### 6. Уменьшить **дублирование** в репозитории
В `sqlite`‑пакете почти каждый репозиторий повторяет шаблон:

```go
type productRepo struct{ db *sql.DB }
func NewProductRepository(db *sql.DB) *productRepo { return &productRepo{db} }
```

Можно вынести базовый тип:

```go
type repo struct{ db *sql.DB }

func newRepo(db *sql.DB) *repo { return &repo{db} }
```

И каждый конкретный репозиторий будет «встраивать» его:

```go
type productRepo struct{ *repo }
func NewProductRepository(db *sql.DB) *productRepo { return &productRepo{newRepo(db)} }
```

Это не меняет поведения, но сокращает количество строк, а значит и количество мест, где может появиться баг.

